CREATE TABLE rag_collections (
                id TEXT PRIMARY KEY,
                name TEXT NOT NULL,
                description TEXT,
                created_at TEXT NOT NULL,
                tags TEXT
            , embedding_provider TEXT, embedding_dimension INTEGER);
CREATE TABLE rag_documents (
                id TEXT PRIMARY KEY,
                collection_id TEXT NOT NULL REFERENCES rag_collections(id) ON DELETE CASCADE,
                filename TEXT NOT NULL,
                source_type TEXT NOT NULL,
                source_url TEXT,
                content_hash TEXT NOT NULL,
                chunk_count INTEGER NOT NULL,
                created_at TEXT NOT NULL,
                size_bytes INTEGER DEFAULT 0,
                tags TEXT,
                page_count INTEGER DEFAULT 0
            );
CREATE TABLE rag_query_analytics (
                id TEXT PRIMARY KEY,
                timestamp TEXT NOT NULL,
                query TEXT NOT NULL,
                collection_ids TEXT,
                mode TEXT,
                result_count INTEGER,
                top_score REAL,
                elapsed_ms REAL
            );
CREATE TABLE voice_audit_log (
        id TEXT PRIMARY KEY,
        timestamp TEXT NOT NULL,
        user_id TEXT,
        event TEXT NOT NULL,
        details TEXT
    );
CREATE TABLE voice_consents (
        voice_id TEXT PRIMARY KEY REFERENCES voices(id) ON DELETE CASCADE,
        signature TEXT NOT NULL,
        consent_document_path TEXT,
        spoken_consent_path TEXT,
        timestamp TEXT NOT NULL
    );
CREATE TABLE voice_model_artifacts (
        voice_id TEXT PRIMARY KEY REFERENCES voices(id) ON DELETE CASCADE,
        language TEXT NOT NULL,
        onnx_path TEXT NOT NULL,
        config_path TEXT NOT NULL
    );
CREATE TABLE voice_owners (
        id TEXT PRIMARY KEY,
        name TEXT NOT NULL,
        email TEXT,
        organization TEXT
    );
CREATE TABLE voice_permissions (
        voice_id TEXT REFERENCES voices(id) ON DELETE CASCADE,
        role TEXT NOT NULL,
        permission TEXT NOT NULL,
        PRIMARY KEY (voice_id, role, permission)
    );
CREATE TABLE voice_samples (
        id TEXT PRIMARY KEY,
        voice_id TEXT REFERENCES voices(id) ON DELETE CASCADE,
        prompt_id TEXT NOT NULL,
        wav_path TEXT NOT NULL,
        status TEXT NOT NULL,
        score INTEGER,
        reason TEXT,
        timestamp TEXT NOT NULL
    );
CREATE TABLE voice_training_jobs (
        id TEXT PRIMARY KEY,
        voice_id TEXT REFERENCES voices(id) ON DELETE CASCADE,
        status TEXT NOT NULL,
        progress REAL DEFAULT 0.0,
        timestamp TEXT NOT NULL
    );
CREATE TABLE voice_usage_events (
        id TEXT PRIMARY KEY,
        timestamp TEXT NOT NULL,
        event_type TEXT NOT NULL,
        details TEXT
    );
CREATE TABLE voices (
        id TEXT PRIMARY KEY,
        name TEXT NOT NULL,
        owner_id TEXT REFERENCES voice_owners(id) ON DELETE CASCADE,
        language TEXT NOT NULL,
        engine TEXT NOT NULL,
        quality_score REAL DEFAULT 0.0,
        status TEXT DEFAULT 'missing_files',
        consent_status TEXT DEFAULT 'pending',
        publish_status TEXT DEFAULT 'unpublished',
        commercial_allowed INTEGER DEFAULT 0
    );
COMMIT;
